{"code":"import json
import re

# Load data
# We must use the keys provided in the previous turns
# books_info key: var_function-call-3643344284243386123
# review key: var_function-call-5656924228622163066

with open('var_function-call-3643344284243386123.json', 'r') as f:
    books_data = json.load(f)

with open('var_function-call-5656924228622163066.json', 'r') as f:
    reviews_data = json.load(f)

book_years = {}
# Regex to match years from 1900 to 2099
year_pattern = re.compile(r'\b(19\d{2}|20\d{2})\b')

for book in books_data:
    b_id_str = book.get('book_id')
    details = book.get('details', '')

    if not b_id_str or not details:
        continue

    # Extract ID number from "bookid_123"
    try:
        if '_' in b_id_str:
            b_id = int(b_id_str.split('_')[1])
        else:
            # Maybe just a number?
            b_id = int(b_id_str)
    except:
        continue

    # Extract Year from details
    years = [int(y) for y in year_pattern.findall(details)]

    if not years:
        continue

    # Take the first year found
    pub_year = years[0]
    book_years[b_id] = pub_year

decade_data = {} # "1980s": {"ratings": [], "books": set()}

for rev in reviews_data:
    p_id_str = rev.get('purchase_id')
    rating_str = rev.get('rating')

    if not p_id_str or rating_str is None:
        continue

    try:
        rating = float(rating_str)
    except:
        continue

    try:
        if '_' in p_id_str:
            p_id = int(p_id_str.split('_')[1])
        else:
            p_id = int(p_id_str)
    except:
        continue

    if p_id in book_years:
        year = book_years[p_id]
        decade_start = (year // 10) * 10
        decade_str = f"{decade_start}s"

        if decade_str not in decade_data:
            decade_data[decade_str] = {'ratings': [], 'books': set()}

        decade_data[decade_str]['ratings'].append(rating)
        decade_data[decade_str]['books'].add(p_id)

results = []
for dec, data in decade_data.items():
    num_books = len(data['books'])
    if num_books >= 10:
        avg_rating = sum(data['ratings']) / len(data['ratings'])
        results.append({'decade': dec, 'avg_rating': avg_rating, 'num_books': num_books})

# Sort by avg_rating desc
results.sort(key=lambda x: x['avg_rating'], reverse=True)

print("__RESULT__:")
print(json.dumps(results))"}

